const body = $input.first().json.body || {};
const mailbox = (body.user_mailbox || '').toLowerCase();
const allowed = (body.allowed_mailboxes || []).map(m => String(m).toLowerCase());
if (!mailbox) {
  throw new Error('user_mailbox is required');
}
if (allowed.length === 0 || !allowed.includes(mailbox)) {
  throw new Error('mailbox_not_in_allowlist: ' + mailbox);
}
return [{ json: $input.first().json }];

const body = $input.first().json;
const values = Array.isArray(body.value) ? body.value : [];
const projectCode = $json.body?.project_code || null;
const allowedMailboxes = $json.body?.allowed_mailboxes || [];

const evidence = values.map((msg, index) => {
  const sender = msg.sender?.emailAddress?.address || '';
  const recipients = (msg.toRecipients || []).map(r => r.emailAddress?.address).filter(Boolean);
  const mailbox = $json.body?.user_mailbox || '';

  const excerpt = (msg.bodyPreview || msg.subject || '').toString().substring(0, 500);
  let hash;
  try {
    const crypto = require('crypto');
    hash = crypto.createHash('sha256').update(msg.id + (msg.internetMessageId || '')).digest('hex');
  } catch (e) {
    hash = 'eml-' + (msg.id || index) + '-' + (msg.receivedDateTime || 'unknown');
  }

  return {
    evidence_id: 'eml-' + (msg.id || index),
    source_type: 'email',
    source_uri: 'https://graph.microsoft.com/v1.0/users/' + encodeURIComponent(mailbox) + '/messages/' + (msg.id || ''),
    title: msg.subject || 'No subject',
    project_code: projectCode,
    contract_no: $json.body?.contract_no || null,
    revision: null,
    timestamp: msg.receivedDateTime || null,
    excerpt: excerpt,
    hash_sha256: hash,
    confidence: 'medium',
    tags: ['email', 'timeline'],
    metadata: {
      sender: sender,
      recipients: recipients,
      mailbox: mailbox,
      has_attachments: msg.hasAttachments || false,
      message_id: msg.internetMessageId || null
    }
  };
});

return [{ json: { evidence: evidence } }];
